class Solution:
    def countGoodRectangles(self, rectangles):
        sides = sorted((min(l, w) for l, w in rectangles), reverse=True)
        best = sides[0]
        count = 0
        for s in sides:
            if s == best:
                count += 1
            else:
                break
        return count

